// Calculate price anchors based on business model
const valueEstimate = parseFloat($json.body.offer_value_estimate) || 10000;
const marketAvg = parseFloat($json.body.market_avg_price) || valueEstimate / 2;
const businessModel = $json.body.business_model || 'subscription';

// Strategy: price points at 33%, 50%, 66% of anchor
const anchor = valueEstimate * 3;
const tier1Price = Math.round(anchor * 0.33 / 50) * 50; // Round to nearest $50
const tier2Price = Math.round(anchor * 0.50 / 100) * 100; // Round to nearest $100
const tier3Price = Math.round(anchor * 0.66 / 100) * 100; // Round to nearest $100

return {
  business_model: businessModel,
  value_estimate: valueEstimate,
  market_avg_price: marketAvg,
  anchor_price: anchor,
  tier1_price: tier1Price,
  tier2_price: tier2Price,
  tier3_price: tier3Price
};

