// Extract Claude response from nested structure
const responseContent = $json.content[0].text;

// Parse JSON from Claude
let pricing;
try {
  pricing = JSON.parse(responseContent);
} catch(e) {
  // If Claude wrapped in markdown backticks, extract it
  const jsonMatch = responseContent.match(/```json\n?(.*?)\n?```/s);
  if (jsonMatch) {
    pricing = JSON.parse(jsonMatch[1]);
  } else if (responseContent.match(/^\{/)) {
    // Try raw object
    pricing = JSON.parse(responseContent);
  } else {
    throw new Error('Invalid JSON from Claude: ' + responseContent.substring(0, 200));
  }
}

// Validate required top-level fields
const requiredFields = [
  'tiers',
  'anchor_strategy',
  'recommended_default_tier',
  'rationale'
];

for (const field of requiredFields) {
  if (pricing[field] === undefined || pricing[field] === null) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Validate tiers array
if (!Array.isArray(pricing.tiers) || pricing.tiers.length !== 3) {
  throw new Error(`Expected exactly 3 tiers, got ${pricing.tiers.length}`);
}

// Validate each tier
for (let i = 0; i < pricing.tiers.length; i++) {
  const tier = pricing.tiers[i];

  const requiredTierFields = [
    'tier_num',
    'tier_name',
    'price',
    'features',
    'target_buyer',
    'anchor_logic',
    'positioning',
    'upsell_path'
  ];

  for (const field of requiredTierFields) {
    if (!tier[field] && tier[field] !== 0) {
      throw new Error(`Tier ${i + 1} missing field: ${field}`);
    }
  }

  // Validate features is array
  if (!Array.isArray(tier.features) || tier.features.length < 3) {
    throw new Error(`Tier ${i + 1} must have minimum 3 features, got ${tier.features.length}`);
  }

  // Validate each feature is non-empty
  for (let j = 0; j < tier.features.length; j++) {
    if (!tier.features[j] || tier.features[j].trim().length === 0) {
      throw new Error(`Tier ${i + 1}, Feature ${j + 1} is empty`);
    }
  }

  // Validate text fields
  if (tier.target_buyer.trim().length === 0) {
    throw new Error(`Tier ${i + 1} target_buyer cannot be empty`);
  }
  if (tier.anchor_logic.trim().length === 0) {
    throw new Error(`Tier ${i + 1} anchor_logic cannot be empty`);
  }
  if (tier.positioning.trim().length === 0) {
    throw new Error(`Tier ${i + 1} positioning cannot be empty`);
  }
  if (tier.upsell_path.trim().length === 0) {
    throw new Error(`Tier ${i + 1} upsell_path cannot be empty`);
  }

  // Extract price as number for validation
  const priceStr = tier.price.replace(/[^0-9.]/g, '');
  const priceNum = parseFloat(priceStr);
  if (isNaN(priceNum) || priceNum <= 0) {
    throw new Error(`Tier ${i + 1} price is invalid: ${tier.price}`);
  }

  // Ensure prices are in ascending order
  if (i > 0) {
    const prevPriceStr = pricing.tiers[i-1].price.replace(/[^0-9.]/g, '');
    const prevPriceNum = parseFloat(prevPriceStr);
    if (priceNum <= prevPriceNum) {
      throw new Error(`Tier prices must be in ascending order. Tier ${i} (${priceNum}) <= Tier ${i-1} (${prevPriceNum})`);
    }
  }
}

// Validate anchor_strategy
if (!pricing.anchor_strategy || pricing.anchor_strategy.trim().length === 0) {
  throw new Error('anchor_strategy cannot be empty');
}

// Validate recommended_default_tier
if (typeof pricing.recommended_default_tier !== 'number' || pricing.recommended_default_tier < 1 || pricing.recommended_default_tier > 3) {
  throw new Error(`recommended_default_tier must be 1, 2, or 3, got ${pricing.recommended_default_tier}`);
}

// Validate rationale
if (!pricing.rationale || pricing.rationale.trim().length === 0) {
  throw new Error('rationale cannot be empty');
}

return pricing;
